import type Column from "./Column.js";
import type { ColumnProperties } from "./Column.js";

export interface EditorColumnProperties extends ColumnProperties {}

export default class EditorColumn extends Column {
  constructor(properties?: EditorColumnProperties);
  /** @since 4.30 */
  get editInfo(): any | null | undefined;
  /**
   * Indicates the column is currently displaying editable inputs in one of its cells.
   *
   * @since 4.30
   */
  get editing(): boolean;
}